  3	import { useODFSystemFlagsSelector } from '@odf/core/redux';
  4	import { ODFSystemFlagsPayload } from '@odf/core/redux/actions';
  5	import { CephBlockPoolModel } from '@odf/shared';
  6	import { ModalFooter } from '@odf/shared/generic/ModalTitle';
  7	import { StatusBox } from '@odf/shared/generic/status-box';
  8	import { useK8sGet } from '@odf/shared/hooks/k8s-get-hook';
  9	import {
 10	  CommonModalProps,
 11	  ModalBody,
 12	  ModalHeader,
 13	} from '@odf/shared/modals/Modal';
 14	import {
 15	  StorageClusterModel,
 16	  PersistentVolumeClaimModel,
 17	  StorageClassModel,
 18	} from '@odf/shared/models';
 19	import { getName, getNamespace } from '@odf/shared/selectors';
 20	import {
 21	  ListKind,
 22	  PersistentVolumeClaimKind,
 23	  StorageClassResourceKind,
 24	  StorageClusterKind,
 25	} from '@odf/shared/types';
 26	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 27	import {
 28	  k8sDelete,
 29	  K8sModel,
 30	  k8sPatch,
 31	  K8sResourceCommon,
 32	  Patch,
 33	  YellowExclamationTriangleIcon,
 34	} from '@openshift-console/dynamic-plugin-sdk';
 35	import * as _ from 'lodash-es';
 36	import { Trans } from 'react-i18next';
 37	import { useLocation, useNavigate } from 'react-router-dom-v5-compat';
 38	import { Modal, ModalVariant } from '@patternfly/react-core';
 39	import {
 40	  getFsPoolIndex,
 41	  getScNamesUsingPool,
 42	  isDefaultPool,
 43	} from '../..//utils';
 44	import {
 45	  ADDITIONAL_FS_POOLS_CLUSTER_CR_PATH,
 46	  PoolProgress,
 47	  PoolType,
 48	} from '../../constants';
 49	import { StoragePoolStatus } from '../../storage-pool/body';
 50	import {
 51	  StoragePoolActionType,
 52	  StoragePoolState,
 53	  blockPoolInitialState,
 54	  storagePoolReducer,
 55	} from '../../storage-pool/reducer';
 56	import { StoragePool } from '../../types';
 57	import { getStorageClassName } from '../../utils/common';
 58	import { StoragePoolModalFooter, FooterPrimaryActions } from './modal-footer';
 59	
 60	const deleteFsPoolRequest = (
 61	  state: StoragePoolState,
 62	  storageCluster: StorageClusterKind
 63	) => {
 64	  const poolIndex = getFsPoolIndex(storageCluster, state.poolName);
 65	
 66	  // NOTE: removing the pool at the CR level should also remove it at the ceph level
 67	  // once this bug is resolved: https://bugzilla.redhat.com/show_bug.cgi?id=2291328
 68	  const patches: Patch[] = [
 69	    {
 70	      op: 'remove',
 71	      path: `${ADDITIONAL_FS_POOLS_CLUSTER_CR_PATH}/${poolIndex}`,
 72	    },
 73	  ];
 74	
 75	  return () =>
 76	    k8sPatch({
 77	      model: StorageClusterModel,
 78	      resource: storageCluster,
 79	      data: patches,
 80	    });
 81	};
 82	
 83	export const toList = (text: string[]): React.ReactNode => (
 84	  <div
 85	    style={{
 86	      overflowY: text.length > 3 ? 'scroll' : 'visible',
 87	      maxHeight: '5rem',
 88	    }}
 89	  >
 90	    {text.map((s) => (
 91	      <li key={s}>{s}</li>
 92	    ))}
 93	  </div>
 94	);
 95	
 96	type DeleteStoragePoolModalProps = CommonModalProps<{
 97	  kindObj?: K8sModel;
 98	  resource: StoragePool;
 99	}>;
100	
101	const DeleteStoragePoolModal: React.FC<DeleteStoragePoolModalProps> = (
102	  props
103	) => {
104	  const { t } = useCustomTranslation();
105	  const { systemFlags, areFlagsLoaded, flagsLoadError } =
106	    useODFSystemFlagsSelector();
107	  const newProps = _.cloneDeep(props);
108	  newProps.extraProps['systemFlags'] = systemFlags;
109	
110	  if (areFlagsLoaded && !flagsLoadError) {
111	    return props?.extraProps?.resource?.type === PoolType.FILESYSTEM ? (
112	      <DeleteFsPoolModal {...(newProps as DeleteFsPoolModalProps)} />
113	    ) : (
114	      <DeleteStoragePoolModalBase
115	        {...(newProps as DeleteStoragePoolModalBaseProps)}
116	      />
117	    );
118	  }
119	  return (
120	    <StatusBox
121	      loaded={areFlagsLoaded}
122	      loadError={flagsLoadError}
123	      label={t('Storage pool delete modal')}
124	    />
125	  );
126	};
127	
128	type DeleteFsPoolModalProps = CommonModalProps<{
129	  kindObj?: K8sModel;
130	  resource: StoragePool;
131	  systemFlags: ODFSystemFlagsPayload['systemFlags'];
132	}>;
133	
134	const DeleteFsPoolModal: React.FC<DeleteFsPoolModalProps> = (props) => {
135	  const { t } = useCustomTranslation();
136	  const {
137	    extraProps: { resource, systemFlags },
138	  } = props;
139	  const poolNamespace = getNamespace(resource);
140	  const clusterName = systemFlags[poolNamespace]?.ocsClusterName;
141	  const [storageCluster, storageClusterLoaded, storageClusterLoadError] =
142	    useSafeK8sGet<StorageClusterKind>(
143	      StorageClusterModel,
144	      clusterName,
145	      poolNamespace
146	    );
147	  const newProps = _.cloneDeep(props);
148	  newProps.extraProps['storageCluster'] = storageCluster;
149	
150	  if (storageClusterLoaded && !storageClusterLoadError) {
151	    return <DeleteStoragePoolModalBase {...newProps} />;
152	  }
153	  return (
154	    <StatusBox
155	      loaded={storageClusterLoaded}
156	      loadError={storageClusterLoadError}
157	      label={t('Storage pool delete modal')}
158	    />
159	  );
160	};
161	
162	type DeleteStoragePoolModalBaseProps = CommonModalProps<{
163	  kindObj?: K8sModel;
164	  resource: StoragePool;
165	  systemFlags: ODFSystemFlagsPayload['systemFlags'];
166	  storageCluster?: StorageClusterKind;
167	}>;
168	
169	const DeleteStoragePoolModalBase: React.FC<DeleteStoragePoolModalBaseProps> = (
170	  props
171	) => {
172	  const { t } = useCustomTranslation();
173	  const {
174	    extraProps: { resource, systemFlags, storageCluster },
175	    isOpen,
176	    closeModal,
177	  } = props;
178	  const poolName = getName(resource);
179	  const poolNamespace = getNamespace(resource);
180	
181	  const [state, dispatch] = React.useReducer(
182	    storagePoolReducer,
183	    blockPoolInitialState
184	  );
185	  const [scNames, setScNames] = React.useState<React.ReactNode>();
186	  const [inProgress, setProgress] = React.useState(false);
187	
188	  const [scResources, scLoaded, scLoadError] =
189	    useK8sGet<ListKind<StorageClassResourceKind>>(StorageClassModel);
190	  const [pvcResources, pvcLoaded, pvcLoadError] = useK8sGet<
191	    ListKind<PersistentVolumeClaimKind>
192	  >(PersistentVolumeClaimModel);
193	
194	  const isExternalSC = systemFlags[poolNamespace]?.isExternalMode;
195	
196	  React.useEffect(() => {
197	    // restrict pool management for default pool and external cluster
198	    isExternalSC || isDefaultPool(resource)
199	      ? dispatch({
200	          type: StoragePoolActionType.SET_POOL_STATUS,
201	          payload: PoolProgress.NOTALLOWED,
202	        })
203	      : dispatch({
204	          type: StoragePoolActionType.SET_POOL_NAME,
205	          payload:
206	            resource.type === PoolType.FILESYSTEM
207	              ? resource.shortName
208	              : poolName,
209	        });
210	  }, [resource, isExternalSC, poolName]);
211	
212	  React.useEffect(() => {
213	    if (scLoaded && pvcLoaded && state.poolStatus !== PoolProgress.NOTALLOWED) {
214	      const poolScNames: string[] = getScNamesUsingPool(
215	        scResources.items,
216	        resource
217	      );
218	      const pvcScNames: string[] = pvcResources.items?.map(getStorageClassName);
219	
220	      // intersection of scNames and pvcScNames
221	      const usedScNames = poolScNames.filter((scName) =>
222	        pvcScNames.includes(scName)
223	      );
224	
225	      if (usedScNames.length) {
226	        dispatch({
227	          type: StoragePoolActionType.SET_POOL_STATUS,
228	          payload: PoolProgress.BOUNDED,
229	        });
230	        setScNames(toList(usedScNames));
231	      }
232	    }
233	  }, [
234	    resource,
235	    scResources,
236	    scLoaded,
237	    pvcResources,
238	    pvcLoaded,
239	    state.poolStatus,
240	    poolName,
241	    t,
242	  ]);
243	
244	  const location = useLocation();
245	  const navigate = useNavigate();
246	  // Delete pool.
247	  const deletePool = () => {
248	    setProgress(true);
249	    let deleteRequest: () => Promise<K8sResourceCommon>;
250	    if (resource.type === PoolType.FILESYSTEM) {
251	      deleteRequest = deleteFsPoolRequest(state, storageCluster);
252	    } else {
253	      deleteRequest = () =>
254	        k8sDelete({
255	          model: CephBlockPoolModel,
256	          resource,
257	          requestInit: null,
258	          json: null,
259	        });
260	    }
261	
262	    deleteRequest().then(() => {
263	      setProgress(false);
264	      closeModal();
265	      // Go to pool list page if pool is deleted.
266	      if (location.pathname.includes(poolName)) {
267	        navigate(location.pathname.split(`/${poolName}`)[0]);
268	      }
269	    });
270	  };
271	
272	  const MODAL_TITLE = (
273	    <ModalHeader>
274	      <YellowExclamationTriangleIcon className="co-icon-space-r" />{' '}
275	      {t('Delete Storage Pool')}
276	    </ModalHeader>
277	  );
278	
279	  const isLoaded = pvcLoaded && scLoaded;
280	  const loadError = pvcLoadError || scLoadError;
281	
282	  return (
283	    <Modal
284	      isOpen={isOpen}
285	      header={MODAL_TITLE}
286	      variant={ModalVariant.small}
287	      onClose={closeModal}
288	    >
289	      {isLoaded && !loadError ? (
290	        <>
291	          <ModalBody>
292	            {state.poolStatus === PoolProgress.NOTALLOWED ? (
293	              <div key="progress-modal">
294	                <StoragePoolStatus
295	                  status={state.poolStatus}
296	                  name={state.poolName}
297	                  error={state.errorMessage}
298	                />
299	              </div>
300	            ) : state.poolStatus === PoolProgress.BOUNDED ? (
301	              <div>
302	                <Trans t={t}>
303	                  <p data-test="pool-bound-message">
304	                    <strong>{{ poolName }}</strong> cannot be deleted. When a
305	                    pool is bounded to PVC it cannot be deleted. Please detach
306	                    all the resources from StorageClass(es):
307	                  </p>
308	                </Trans>
309	                <strong>
310	                  <ul data-test="pool-storage-classes">{scNames}</ul>
311	                </strong>
312	              </div>
313	            ) : (
314	              <Trans t={t}>
315	                <p>
316	                  Deleting <strong>{{ poolName }}</strong> will remove all the
317	                  saved data of this pool. Are you sure want to delete?
318	                </p>
319	              </Trans>
320	            )}
321	          </ModalBody>
322	          <ModalFooter inProgress={inProgress}>
323	            <StoragePoolModalFooter
324	              state={state}
325	              dispatch={dispatch}
326	              onSubmit={deletePool}
327	              cancel={closeModal}
328	              close={closeModal}
329	              primaryAction={FooterPrimaryActions(t).DELETE}
330	            />
331	          </ModalFooter>
332	        </>
333	      ) : (
334	        <StatusBox
335	          loaded={isLoaded}
336	          loadError={loadError}
337	          label={t('Storage pool delete modal')}
338	        />
339	      )}
340	    </Modal>
341	  );
342	};
343	
344	export default DeleteStoragePoolModal;

